    private fun sanitizeData(data: String): String {
        var sanitized = data
        
        sensitivePatterns.forEach { (pattern, replacement) ->
            val regex = Regex("\"$pattern\"\\s*:\\s*\"([^\"]+)\"", RegexOption.IGNORE_CASE)
            sanitized = when (replacement) {
                is String -> sanitized.replace(regex, "\"$pattern\": \"$replacement\"")
                is Function1<*, *> -> {
                    regex.replace(sanitized) { matchResult ->
                        val value = matchResult.groupValues[1]
                        "\"$pattern\": \"${(replacement as Function1<String, String>)(value)}\""
                    }
                }
                else -> sanitized
            }
        }
        
        val emailRegex = Regex("\\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Z|a-z]{2,}\\b")
        sanitized = sanitized.replace(emailRegex) { maskEmail(it.value) }
        
        val phoneRegex = Regex("\\b\\d{3}[-.]?\\d{3}[-.]?\\d{4}\\b")
        sanitized = sanitized.replace(phoneRegex) { maskPhone(it.value) }
        
        val creditCardRegex = Regex("\\b\\d{4}[\\s-]?\\d{4}[\\s-]?\\d{4}[\\s-]?\\d{4}\\b")
        sanitized = sanitized.replace(creditCardRegex, "****-****-****-****")
        
        return sanitized
    }
    
    private fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***.***"
        val localPart = parts[0]
        val domain = parts[1]
        val maskedLocal = if (localPart.length > 2) {
            "${localPart[0]}***${localPart.last()}"
        } else {
            "***"
        }
        return "$maskedLocal@$domain"
    }
    
    private fun maskPhone(phone: String): String {
        val digits = phone.filter { it.isDigit() }
        return if (digits.length >= 4) {
            "***-***-${digits.takeLast(4)}"
        } else {
            "***-***-****"
        }
    }
    
    private fun hashSensitiveData(data: String): String {
        return try {
            val digest = MessageDigest.getInstance("SHA-256")
            val hash = digest.digest(data.toByteArray())
            hash.joinToString("") { "%02x".format(it) }.take(16)
        } catch (e: Exception) {
            "HASH_ERROR"
        }
    }
    
    fun logAuthAttempt(
