    fun exportLogs(callback: (File?) -> Unit) {
        logScope.launch {
            try {
                val logsDir = File(context.filesDir, "logs")
                if (!logsDir.exists()) {
                    callback(null)
                    return@launch
                }
                
                val exportFile = File(context.cacheDir, "exported_logs_${System.currentTimeMillis()}.txt")
                val writer = FileWriter(exportFile)
                
                logsDir.listFiles()?.sortedByDescending { it.lastModified() }?.forEach { logFile ->
                    writer.append("=== ${logFile.name} ===\n")
                    writer.append(logFile.readText())
                    writer.append("\n\n")
                }
                
                writer.close()
                callback(exportFile)
            } catch (e: Exception) {
                Timber.e("Failed to export logs: ${e.message}")
                callback(null)
            }
        }
    }
    
    fun clearLogs() {
        logScope.launch {
            try {
                val logsDir = File(context.filesDir, "logs")
                logsDir.listFiles()?.forEach { it.delete() }
                Timber.i("Logs cleared successfully")
            } catch (e: Exception) {
