            }
        }
    }
    
    private class DebugTree : Timber.DebugTree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            super.log(priority, "SecureLogger", message, t)
        }
    }
    
    private class ProductionTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            if (priority >= Log.INFO) {
                Log.println(priority, "SecureLogger", message)
                t?.let { Log.println(priority, "SecureLogger", it.stackTraceToString()) }
            }
        }
    }
    
    private class FileLoggingTree(private val context: Context) : Timber.Tree() {
        private val logScope = CoroutineScope(Dispatchers.IO)
        private val dateFormat = SimpleDateFormat("yyyy-MM-dd", Locale.US)
        
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            logScope.launch {
                try {
                    val logsDir = File(context.filesDir, "logs")
                    if (!logsDir.exists()) {
                        logsDir.mkdirs()
                    }
                    
                    val logFileName = "log_${dateFormat.format(Date())}.txt"
                    val logFile = File(logsDir, logFileName)
                    
                    val priorityString = when (priority) {
                        Log.VERBOSE -> "V"
                        Log.DEBUG -> "D"
                        Log.INFO -> "I"
                        Log.WARN -> "W"
                        Log.ERROR -> "E"
                        else -> "?"
                    }
                    
                    val timestamp = SimpleDateFormat("HH:mm:ss.SSS", Locale.US).format(Date())
                    val logEntry = "[$timestamp] $priorityString: $message\n"
                    
                    logFile.appendText(logEntry)
                    
                    t?.let {
                        logFile.appendText("${it.stackTraceToString()}\n")
                    }
                    
                    if (logFile.length() > MAX_LOG_SIZE) {
                        rotateLogFiles(logsDir)
                    }
                } catch (e: Exception) {
                    Log.e("FileLoggingTree", "Failed to write log: ${e.message}")
                }
            }
        }
        
        private fun rotateLogFiles(logsDir: File) {
            val logFiles = logsDir.listFiles()?.sortedByDescending { it.lastModified() } ?: return
            
            if (logFiles.size >= MAX_LOG_FILES) {
                logFiles.drop(MAX_LOG_FILES - 1).forEach { it.delete() }
            }
        }
    }
