class DatabaseLogger {
    companion object {
        fun logQuery(query: String, params: List<Any?> = emptyList(), executionTime: Long = 0) {
            SecureLogger.logDatabaseQuery(query, params, executionTime)
        }
        
        fun logInsert(table: String, values: Map<String, Any?>, executionTime: Long = 0) {
            val query = "INSERT INTO $table"
            SecureLogger.logDatabaseQuery(query, values.values.toList(), executionTime, 1)
        }
        
        fun logUpdate(table: String, values: Map<String, Any?>, where: String, executionTime: Long = 0) {
            val query = "UPDATE $table SET ... WHERE $where"
            SecureLogger.logDatabaseQuery(query, values.values.toList(), executionTime)
        }
        
        fun logDelete(table: String, where: String, executionTime: Long = 0) {
            val query = "DELETE FROM $table WHERE $where"
            SecureLogger.logDatabaseQuery(query, emptyList(), executionTime)
        }
    }
}

